import React, { useState } from 'react';
import { Lock, User, Zap } from 'lucide-react';

const Login = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    // Hardcoded credentials as requested
    if (email === 'mh15sohail@gmail.com' && password === '16301003') {
      onLogin();
    } else {
      setError('Invalid email or password');
    }
  };

  return (
    <div className="max-w-md mx-auto mt-20">
      <div className="glass p-10 rounded-3xl border border-white/10 shadow-2xl">
        <div className="flex flex-col items-center mb-8">
          <div className="bg-yellow-500 p-4 rounded-2xl mb-4 shadow-[0_0_20px_rgba(234,179,8,0.3)]">
            <Zap className="text-black" size={32} fill="currentColor" />
          </div>
          <h2 className="text-3xl font-bold gold-text-gradient">Admin Login</h2>
          <p className="text-gray-400 mt-2 text-center">Enter your credentials to manage services</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-400 flex items-center gap-2">
              <User size={16} /> Email Address
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-black/30 border border-gray-700 rounded-xl p-3 focus:border-yellow-500 outline-none transition"
              placeholder="sohail@electricals.com"
              required
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-400 flex items-center gap-2">
              <Lock size={16} /> Password
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-black/30 border border-gray-700 rounded-xl p-3 focus:border-yellow-500 outline-none transition"
              placeholder="••••••••"
              required
            />
          </div>

          {error && <p className="text-red-500 text-sm text-center">{error}</p>}

          <button
            type="submit"
            className="w-full py-4 gold-gradient rounded-xl text-black font-black text-lg hover:shadow-[0_0_30px_rgba(234,179,8,0.3)] transition-all"
          >
            LOGIN
          </button>
        </form>

        <div className="mt-8 pt-6 border-t border-gray-800 text-center">
          <p className="text-xs text-gray-500">
            Forgot password? Contact system administrator.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
